form:Form.form:Scripts:
		var TIPOSHORA=null;

function FindHora(id_hora)
{
	var t;
	if (TIPOSHORA==null)
	{
		proxy=new NomadProxy();
		TIPOSHORA=proxy.SQLService().GetOBJ(Ctrl("main").getResource("TIPOS_DE_HORAS"),"");
	}

	for (t=0; t<TIPOSHORA.Child.length; t++)
		if (TIPOSHORA.Child[t].id==id_hora) return TIPOSHORA.Child[t];

	return null;
} 

function DrawReference(arr, ContainerName)
{                         
	var HTMLoutput="", key;
	var TrgObj=document.getElementById(ContainerName);

	HTMLoutput+="<TABLE style='width:100%;height:100%cursor:default;font-family:arial;font-size:10px;font-weight:bold;color:#000000;background-color:#F0F0D0;border: 1px solid black;' >";
	for (key in arr)
		HTMLoutput+="<TR style='height:20px;' >"
		           +"<TD style='border-bottom:1px dotted #808080;width:30px;font-size:1px;' ><div style='padding:0px;height:12px;border-left:2px solid #"+arr[key].color+";border-right:2px solid #"+arr[key].color+";' ><div style='position:relative;top:4px;height:4px;width:100%;background-color:#"+arr[key].color+";' ></div></div></TD>"
		           +"<TD style='border-bottom:1px dotted #808080;' >"+arr[key].label+"</TD>"
		           +"<TD style='border-bottom:1px dotted #808080;' >"+arr[key].value+"</TD>"
		           +"</TR>";
	HTMLoutput+="</TABLE>";

	TrgObj.innerHTML=HTMLoutput;
}

function DrawGraphics()
{        

	var HTMLoutput="", TrgObj;
	HTMLoutput+="<TABLE style='width:100%;height:100%cursor:default;font-family:arial;font-size:10px;font-weight:bold;color:#000000;' >";
	HTMLoutput+="<TR>"
	           +"<TD>Cargando...</TD>"
	           +"</TR>";
	HTMLoutput+="</TABLE>";


	TrgObj=document.getElementById("Reference1");
	TrgObj.innerHTML=HTMLoutput;

	TrgObj=document.getElementById("Reference2");
	TrgObj.innerHTML=HTMLoutput;      

	TrgObj=document.getElementById("Contenedor");
	TrgObj.innerHTML=HTMLoutput;      

	window.setTimeout("ReDrawGraphics();", 500);
}

function ReDrawGraphics()
{
	proxy=new NomadProxy();
	PERSONA    =proxy.DDOService().GetOBJ("NucleusRH.Base.Tiempos_Trabajados.Liquidacion_Personas.LIQUIDACIONPERS", Ctrl("oi_liquidacionpers").GetXValue());
	LIQUIDACION=proxy.DDOService().GetOBJ("NucleusRH.Base.Tiempos_Trabajados.Liquidacion.LIQUIDACION", PERSONA.LIQUIDACIONPERS.oi_liquidacion.value);

	MyOBJ=HTMLTimeBar("Contenedor","",null,null);
	MyOBJ.AddSerie("ESTADO","Est");


	MyOBJ.SetAxisDate2(LIQUIDACION.LIQUIDACION.f_fechainicio,LIQUIDACION.LIQUIDACION.f_fechafin);
	MyOBJ.SetAxisTime(-6*60, 30*60, 60, 15, 3);

	ValAnt="00";
	FechaDesde=str2date(LIQUIDACION.LIQUIDACION.f_fechainicio);
	FechaHasta=str2date(LIQUIDACION.LIQUIDACION.f_fechainicio);

	HorariosList=new Array();
	DiasList    =new Array();
	Dias		    =new Array();

	for (d=str2date(LIQUIDACION.LIQUIDACION.f_fechainicio); d<=str2date(LIQUIDACION.LIQUIDACION.f_fechafin); d.setDate(d.getDate() + 1)) 
	{
		MyJOR=new Object();
		MyJOR.l_esperado="0";
		MyJOR.l_presente="0";
		MyJOR.f_fecjornada=date2str(d);
		Dias[d] = MyJOR;
	}	 
	MyJOR=new Object();
	MyJOR.l_esperado="0";
	MyJOR.l_presente="0";
	MyJOR.f_fecjornada="19760115";

	Dias[str2date("19760115")] = MyJOR;

	for (t=0; t<PERSONA.LIQUIDACIONPERS.LIQUIDACJOR.Child.length; t++)
	{ 
		MyJOR=PERSONA.LIQUIDACIONPERS.LIQUIDACJOR.Child[t];
		Dias[str2date(MyJOR.f_fecjornada)] = MyJOR;	
	}

	for (d in Dias)
	{		
		MyJOR=Dias[d];

		ValNew=MyJOR.l_esperado+MyJOR.l_presente;

		if (ValAnt==ValNew)
			FechaHasta=str2date(MyJOR.f_fecjornada);
		else
		{						
			switch(ValAnt)
			{
				case "00": //No tiene que venir y no vino (no hay que hacer nada)         					
					MyOBJDIA = new Object();
				break;
				case "10": //Tiene que venir y no vino (AUSENTE)
					MyOBJ.SetSerieValue("ESTADO",date2str(FechaDesde),date2str(FechaHasta)," ", "C0A0A0", "000000", "Ausente desde "+FechaDesde.getDate()+"/"+(FechaDesde.getMonth()+1)+"/"+FechaDesde.getFullYear()+" hasta "+FechaHasta.getDate()+"/"+(FechaHasta.getMonth()+1)+"/"+FechaHasta.getFullYear());
					if (DiasList["AUS"]?false:true) DiasList["AUS"]=new Object();
					MyOBJDIA=DiasList["AUS"];
					MyOBJDIA.label="Ausente";
					MyOBJDIA.color="C0A0A0";
				break;
				case "11": //Tiene que venir y vino (PRESENTE)
					MyOBJ.SetSerieValue("ESTADO",date2str(FechaDesde),date2str(FechaHasta)," ", "80C080", "000000", "Presente desde "+FechaDesde.getDate()+"/"+(FechaDesde.getMonth()+1)+"/"+FechaDesde.getFullYear()+" hasta "+FechaHasta.getDate()+"/"+(FechaHasta.getMonth()+1)+"/"+FechaHasta.getFullYear());
					if (DiasList["PRE"]?false:true) DiasList["PRE"]=new Object();
					MyOBJDIA=DiasList["PRE"];
					MyOBJDIA.label="Presente";
					MyOBJDIA.color="80C080";
				break;
				case "01": //No tiene que venir y vino! (EXEDENTE)
					MyOBJ.SetSerieValue("ESTADO",date2str(FechaDesde),date2str(FechaHasta)," ", "AAAA40", "000000", "Excedente desde "+FechaDesde.getDate()+"/"+(FechaDesde.getMonth()+1)+"/"+FechaDesde.getFullYear()+" hasta "+FechaHasta.getDate()+"/"+(FechaHasta.getMonth()+1)+"/"+FechaHasta.getFullYear());
					if (DiasList["EXE"]?false:true) DiasList["EXE"]=new Object();
					MyOBJDIA=DiasList["EXE"];
					MyOBJDIA.label="Excedente";
					MyOBJDIA.color="AAAA40";

				break;
			}         

			if (MyOBJDIA.Total?false:true) MyOBJDIA.Total=0;
			MyOBJDIA.Total+=1+Math.floor((FechaHasta-FechaDesde)/86400000);

			ValAnt=ValNew;
			FechaDesde=str2date(MyJOR.f_fecjornada);
			FechaHasta=str2date(MyJOR.f_fecjornada);
		}         

		if (MyJOR.LIQUIDACPROC)                          
		{           
			for (d=0; d<MyJOR.LIQUIDACPROC.Child.length; d++)
			{
				MyDET=MyJOR.LIQUIDACPROC.Child[d];
				MyHOR=FindHora(MyDET.oi_tipohora.value);

				if (MyHOR==null)
				{
					MyHOR=new Object();
					MyHOR.color="000000";
					MyHOR.label="Desconocida";
				}

				HD=(str2datetime(MyDET.f_fechoraentrada)-str2date(MyJOR.f_fecjornada))/60000;
				HH=(str2datetime(MyDET.f_fechorasalida )-str2date(MyJOR.f_fecjornada))/60000;

				HDtxt=parseInt((HD+1440)%1440/60,10)+":"+FillLeft(((HD+1440)%60).toString(),2,"0");
				HHtxt=parseInt((HH+1440)%1440/60,10)+":"+FillLeft(((HH+1440)%60).toString(),2,"0");

	   		//Agrego el Horario a la Lista de Referencias
				HorariosList[MyHOR.id.toString()]=MyHOR;
				if (MyHOR.Total?false:true) MyHOR.Total=0;
				MyHOR.Total+=Math.floor(HH-HD);

				MyOBJ.SetValue(MyJOR.f_fecjornada, 
				               HD, 
				               HH, 
				               " ", 
				               MyHOR.color, 
				               "000000", 
				               MyHOR.label+" desde "+HDtxt+" hasta "+HHtxt);

			}
		}

	}     

	for (key in DiasList) DiasList[key].value=DiasList[key].Total+" dias.";
	for (key in HorariosList) HorariosList[key].value=Math.floor(HorariosList[key].Total/60)+":"+FillLeft((HorariosList[key].Total%60).toString(),2,"0")+" Hs.";

	DrawReference(DiasList    ,"Reference1");
	DrawReference(HorariosList,"Reference2");
	MyOBJ.Draw();
}
